    int peak_index = 0;
    for (int i = 1; i < n; ++i) {
        if (nums[i] > nums[i-1]) {
            peak_index = i;
        } else {
            // 找到第一个不递增的位置，即峰值在 i-1
            // 由于数组是双调的，一旦开始不递增，峰值就是上一个点。
            // 实际上，如果 nums[i] <= nums[i-1]，那么 i-1 就是峰值（除非 i-1 是开头）。
            // 我们需要找到最大的 i 使得 nums[i] > nums[i-1]。
            // 我们可以继续遍历直到 nums[i] < nums[i-1] 或 i == n-1

            // 更稳妥的方法是找到转折点：
            // 递增阶段：nums[i] > nums[i-1]
            // 递减阶段：nums[i] < nums[i-1]
            // 峰值就是递增停止，递减开始的那个点。
