        if (n == 1) return -1;
        // 如果 n=2, 只能是严格递增或严格递减，峰值在后面。
        // 假设 n=2, [a, b]
        // 如果 a < b (严格递增)，峰值是 b. 增=[a,b], 减=[b]. Sum_inc = a+b, Sum_dec = b.
        // 如果 a > b (严格递减)，峰值是 a. 增=[a], 减=[a,b]. Sum_inc = a, Sum_dec = a+b.
        // 由于题目保证是双调的，并且定义了严格递增/递减的特性，
        // 我们需要找到峰值。对于 n=2，峰值一定是索引 1（如果递增）或索引 0（如果递减）。
        // 但是题目保证双调，并且峰值存在，我们应该能找到。
    }

    // 1. 找到峰值元素 (Peak Index)
    int peak_index = 0;
    for (int i = 1; i < n; ++i) {
        if (nums[i] > nums[i-1]) {
            peak_index = i;
        } else {
            // 找到第一个不递增的位置，即峰值在 i-1
            // 由于数组是双调的，一旦开始不递增，峰值就是上一个点。
            // 实际上，如果 nums[i] <= nums[i-1]，那么 i-1 就是峰值（除非 i-1 是开头）。
            // 我们需要找到最大的 i 使得 nums[i] > nums[i-1]。
            // 我们可以继续遍历直到 nums[i] < nums[i-1] 或 i == n-1

            // 更稳妥的方法是找到转折点：
            // 递增阶段：nums[i] > nums[i-1]
            // 递减阶段：nums[i] < nums[i-1]
            // 峰值就是递增停止，递减开始的那个点。
            // 遍历直到 nums[i] < nums[i-1]
            // 如果我们在这里 break，peak_index 存储的就是最后一个递增的点（即峰值）。
            break;
        }
    }

    // 再次确保找到的 peak_index 是正确的。
    // 如果数组完全严格递增，peak_index = n-1。
    // 如果数组完全严格递减，peak_index = 0。
    // 我们的循环逻辑：
    // 1. 如果所有元素都递增 (e.g., [1, 2, 3]), loop finishes, peak_index = n-1. (Correct)
    // 2. 如果所有元素都递减 (e.g., [3, 2, 1]), peak_index remains 0, because nums[1] <= nums[0]. (Correct)
    // 3. 如果是双调 (e.g., [1, 3, 2]):
    //    i=1: 3 > 1, peak_index = 1.
    //    i=2: 2 < 3, break. peak_index = 1. (Correct)

    // 2. 计算递增部分的和 (Sum_Inc): [0, peak_index]
    int64 sum_inc = 0;
    for (int i = 0; i <= peak_index; ++i) {
        sum_inc += nums[i];
    }

    // 3. 计算递减部分的和 (Sum_Dec): [peak_index, n-1]
    int64 sum_dec = 0;
    for (int i = peak_index; i < n; ++i) {
        sum_dec += nums[i];
    }

    // 4. 比较和并返回结果
    if (sum_inc > sum_dec) {
        return 0;
    } else if (sum_dec > sum_inc) {
        return 1;
    } else {
        return -1;
    }
}
